package main

import (
	"fmt"
	"reflect"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with the order object injected as a global 'order' variable, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Deep copy the order to prevent modifications to the original map from the script
	var copiedOrder interface{}
	if order != nil {
		copiedOrder = deepCopy(order)
	}

	// Inject the order object as a global variable named 'order' in the VM
	err := vm.Set("order", copiedOrder)
	if err != nil {
		return 0.0, fmt.Errorf("failed to inject order into VM: %w", err)
	}

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64, handling all numeric types (including custom aliases)
	exported := result.Export()
	rv := reflect.ValueOf(exported)
	var discount float64

	switch rv.Kind() {
	case reflect.Int, reflect.Int8, reflect.Int16, reflect.Int32, reflect.Int64:
		discount = float64(rv.Int())
	case reflect.Uint, reflect.Uint8, reflect.Uint16, reflect.Uint32, reflect.Uint64, reflect.Uintptr:
		discount = float64(rv.Uint())
	case reflect.Float32, reflect.Float64:
		discount = rv.Float()
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", exported)
	}

	return discount, nil
}

// deepCopy creates a deep copy of the input, handling maps, slices, and primitive types.
// It is intended for use with JSON-serializable order data and does not handle cycles
// or non-serializable types like pointers, channels, or functions.
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copied := make(map[string]interface{}, len(val))
		for k, v := range val {
			copied[k] = deepCopy(v)
		}
		return copied
	case []interface{}:
		copied := make([]interface{}, len(val))
		for i, v := range val {
			copied[i] = deepCopy(v)
		}
		return copied
	default:
		// Primitive types, value structs, etc. are copied by value
		return val
	}
}

