const scriptExecutionTimeout = 1 * time.Second

// deepCopy performs a deep copy of common JSON-supported types (maps, slices, basic types)
// to prevent the JavaScript script from modifying the original order data.
func deepCopy(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		copiedMap := make(map[string]interface{}, len(val))
		for k, v := range val {
			copiedMap[k] = deepCopy(v)
		}
		return copiedMap
	case []interface{}:
		copiedSlice := make([]interface{}, len(val))
		for i, v := range val {
			copiedSlice[i] = deepCopy(v)
		}
		return copiedSlice
	default:
		// Basic types (int, float, bool, string, nil) are passed by value, no copy needed
		return val
	}
}

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with the order map injected as a global "order" variable. The value of the last expression
// in the script is used as the discount amount. Return statements are not allowed
// as the script runs in global scope.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject the entire order map as a global "order" variable in the VM
	copiedOrder := deepCopy(order)
	err := vm.Set("order", copiedOrder)
	if err!= nil {
		return 0.0, fmt.Errorf("failed to inject order object: %w", err)
	}

	// Create context with timeout to prevent infinite loops from hanging the program
	ctx, cancel := context.WithTimeout(context.Background(), scriptExecutionTimeout)
	defer cancel()

	// Execute the script with timeout handling
	done := make(chan struct {
		result goja.Value
		err    error
	}, 1)
	go func() {
		res, err := vm.RunString(script)
		done <- struct {
			result goja.Value
			err    error
		}{res, err}
	}()

	var result goja.Value
	var err error
	select {
	case <-ctx.Done():
		// Interrupt the running script
		vm.Interrupt(ctx.Err())
		// Wait for the goroutine to exit
		<-done
		return 0.0, fmt.Errorf("script execution timed out after %v: %w", scriptExecutionTimeout, ctx.Err())
	case res := <-done:
		result = res.result
		err = res.err
	}

	if err!= nil {
		return 0.0, fmt.Errorf("script execution failed: %w", err)
	}

	// Export the result once to avoid redundant processing
	exportedResult := result.Export()

	// Try direct conversion to float64 first (most common case for JS numbers)
